from functools import wraps
import time

def timeout(timeout_duration):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            start = time.time()
            result = func(*args, **kwargs)
            if time.time() - start > timeout_duration:
                raise TimeoutError("Function call timed out")
            return result
        return wrapper
    return decorator

